import{_ as n,c as e,a1 as a,o as h}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Ẩn Dữ liệu sử dụng Steganography","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/9-Steganography.md"};function o(g,t,c,r,s,l){return h(),e("div",null,t[0]||(t[0]=[a('<h1 id="an-du-lieu-su-dung-steganography" tabindex="-1">Ẩn Dữ liệu sử dụng Steganography <a class="header-anchor" href="#an-du-lieu-su-dung-steganography" aria-label="Permalink to &quot;Ẩn Dữ liệu sử dụng Steganography&quot;">​</a></h1><p>Steganography là kỹ thuật giấu một file, thông điệp, hình ảnh hoặc video bên trong một file, thông điệp, hình ảnh hoặc video khác.</p><p>Steganography mạng mô tả tất cả các phương pháp được sử dụng để truyền dữ liệu qua mạng mà không bị phát hiện. Một số phương pháp ẩn dữ liệu trong mạng đã được đề xuất, nhưng nhược điểm chính của hầu hết chúng là không cung cấp lớp bảo mật thứ hai. Nếu steganography để truyền thông tin nhạy cảm ra khỏi hệ thống mục tiêu mà không bị phát hiện.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Sử dụng Steganography trong Windows và Linux.</li><li>Sử dụng Snow steganography để ẩn file và dữ liệu.</li><li>ẩn file sử dụng khoảng trắng và tab.</li><li>Ẩn thông điệp văn bản bí mật trong hình ảnh sử dụng OpenStego.</li></ul><h2 id="an-du-lieu-su-dung-snow-windows" tabindex="-1">Ẩn Dữ liệu sử dụng Snow (Windows) <a class="header-anchor" href="#an-du-lieu-su-dung-snow-windows" aria-label="Permalink to &quot;Ẩn Dữ liệu sử dụng Snow (Windows)&quot;">​</a></h2><p>Trang web Snow: <a href="http://darkside.com.au/snow/index.html" target="_blank" rel="noreferrer">http://darkside.com.au/snow/index.html</a></p><p>Snow được sử dụng để giấu thông điệp trong văn bản ASCII bằng cách thêm khoảng trắng vào cuối dòng. Vì khoảng trắng và tab thường không hiển thị trong trình xem văn bản, thông điệp được ẩn hiệu quả khỏi người xem thông thường. Và nếu mã hóa tích hợp được sử dụng, thông điệp không thể đọc được ngay cả khi bị phát hiện.</p><p>Snow khai thác bản chất steganography của khoảng trắng. Tìm khoảng trắng cuối dòng trong văn bản giống như tìm gấu trắng trong bão tuyết, nó sử dụng thuật toán mã hóa ICE, vì vậy tên nhất quán về chủ đề.</p><p><strong>Mã hóa ICE</strong>: Thuật toán mã hóa này là một block cipher 64-bit. Nó chạy ở chế độ 1-bit cipher-feedback (CFB), mặc dù không hiệu quả (yêu cầu mã hóa 64-bit đầy đủ cho mỗi bit output).</p><ol><li><p>Khởi chạy <strong>command prompt</strong> và điều hướng đến thư mục Snow. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1e1e57a1a30bab7ad94f502b3bba5107098448c0/snow-01.png" alt="snow-01"></p></li><li><p>Tạo file readme.txt <strong>bên trong thư mục SNOW</strong> với một thông điệp ngẫu nhiên như: <code>hello world!</code></p></li><li><p>Bây giờ quay lại <strong>command prompt</strong> và tạo thông tin bí mật <code>snow -C -m &quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot; -p &quot;pa55&quot; readme.txt readme2.txt</code></p></li></ol><p><code>-m &quot;message&quot;</code>: chuỗi bí mật <code>pa55</code>: là mật khẩu, bạn có thể nhập bất kỳ mật khẩu nào bạn muốn. <code>readme2.txt</code>: là tên của một file khác sẽ được tạo tự động tại cùng vị trí.</p><p>Bây giờ dữ liệu (<code>&quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot;</code>) được ẩn bên trong file <strong>readme2.txt</strong> với nội dung của <strong>readme.txt</strong>.</p><p><em>readme2.txt = readme.txt + &quot;My sketchy wallet: 3FkenCiXpSLqD8L79intRNXUgjRoH9sjXy&quot;</em></p><p><strong>Bạn có thể mở cả readme.txt và readme2.txt để kiểm tra xem có sự khác biệt nào không</strong>, ngoài khoảng trắng như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1e1e57a1a30bab7ad94f502b3bba5107098448c0/snow-whitespaces-02.png" alt="whitespaces-difference"></p><ol start="4"><li>Để hiển thị nội dung bị ẩn, nhập: <code>snow -C -p &quot;pa55&quot; readme2.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/346be861372d685fe81d0a7dd3d9cb7687c2592a/snow-03.png" alt="snow3"></li></ol><hr><h1 id="steganography-hinh-anh-su-dung-openstego-windows" tabindex="-1">Steganography Hình ảnh sử dụng OpenStego (Windows) <a class="header-anchor" href="#steganography-hinh-anh-su-dung-openstego-windows" aria-label="Permalink to &quot;Steganography Hình ảnh sử dụng OpenStego (Windows)&quot;">​</a></h1><p>OpenStego là công cụ steganography ẩn dữ liệu bên trong hình ảnh. OpenStego là ứng dụng dựa trên Java và hỗ trợ mã hóa dữ liệu dựa trên mật khẩu để tăng cường bảo mật. Nó sử dụng thuật toán DES để mã hóa dữ liệu, kết hợp với băm MDS để tạo khóa DES từ mật khẩu được cung cấp.</p><p>Trang web OpenStego: <a href="https://www.openstego.com/" target="_blank" rel="noreferrer">https://www.openstego.com/</a></p><ol><li><p>Cài đặt OpenStego và Mở ứng dụng <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2a94c49858a92a09855df3edab939b2d731b8b8f/openstego-1.png" alt="OpenStego-1"></p></li><li><p>Nhấp vào <strong>nút ellipsis</strong> trên ô nhập <strong>Message File</strong> và chọn file text có trong thư mục OpenStego (File text này chứa thông tin nhạy cảm &#39;giả&#39; như số VISA và mã PIN). <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3ece1184799bc34f54c0523fa8c0b6bd6efe9f30/openstego-2.png" alt="OpenSTego-2"></p></li><li><p>Tiếp theo, nhấp vào <strong>nút ellipsis</strong> thứ hai (<strong>Cover File</strong>) và chọn <strong>Island.jpg</strong> cũng nằm trong thư mục OpenStego. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ef22f60c5f3883f11031c0e2c3e18835e246c578/openStego-3.png" alt="OpenStego-3"></p></li><li><p>Nhấp vào <strong>nút ellipsis</strong> thứ ba <strong>(Output Stego File)</strong>, chọn <strong>Desktop</strong> và đặt tên file là <strong>stego</strong>.</p></li><li><p>Bây giờ, nhấp <strong>Hide Data</strong> ở góc dưới bên phải. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6bcf0fc1ad730e4b8bfb0f29695cd3d5da026db4/openStego-5.png" alt="OpenStego-5"></p></li></ol><p>Mở file hình ảnh trên desktop, bạn sẽ chỉ thấy hình ảnh mà không thấy nội dung thông điệp (file text) được nhúng vào, như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/8265b66f9795426b604a8b602df5027d27a69897/stego-6.png" alt="OpenStego-6"></p><h3 id="thu-thap-file-text-tu-hinh-anh" tabindex="-1">Thu thập File Text từ Hình ảnh <a class="header-anchor" href="#thu-thap-file-text-tu-hinh-anh" aria-label="Permalink to &quot;Thu thập File Text từ Hình ảnh&quot;">​</a></h3><ol><li><p>Quay lại cửa sổ OpenStego và nhấp nút <strong>Extract Data</strong> ở góc trái.</p></li><li><p>Nhấp vào <strong>nút ellipsis</strong> đầu tiên <strong>(Input Stego File)</strong>, chọn hình ảnh bạn đã tạo từ <strong>Desktop</strong> và <strong>Output Folder</strong> trên nút ellipsis tiếp theo. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/80722e31e7a359444d428f12b87bf31d64cfb739/openstego-7.png" alt="openstego7"></p></li><li><p>Nhấp <strong>Extract Data</strong> ở góc dưới bên phải. Thao tác này sẽ trích xuất file thông điệp từ hình ảnh.</p></li><li><p>File hiển thị tất cả thông tin chứa trong tài liệu, như hình dưới đây: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/80722e31e7a359444d428f12b87bf31d64cfb739/openstego-8.png" alt="openstego8"></p></li></ol><hr><h1 id="su-dung-quick-stego-windows" tabindex="-1">Sử dụng Quick Stego (Windows) <a class="header-anchor" href="#su-dung-quick-stego-windows" aria-label="Permalink to &quot;Sử dụng Quick Stego (Windows)&quot;">​</a></h1><p>Quick Stego ẩn văn bản trong hình ảnh sao cho chỉ những người dùng Quick Stego khác mới có thể truy xuất và đọc các thông điệp bí mật bị ẩn.</p><p>Trang web QuickStego: <a href="http://quickcrypto.com/free-steganography-software.html" target="_blank" rel="noreferrer">http://quickcrypto.com/free-steganography-software.html</a></p><h3 id="an-van-ban-ben-trong-hinh-anh" tabindex="-1">Ẩn văn bản bên trong hình ảnh <a class="header-anchor" href="#an-van-ban-ben-trong-hinh-anh" aria-label="Permalink to &quot;Ẩn văn bản bên trong hình ảnh&quot;">​</a></h3><ol><li><p>Cài đặt Quick Stego.</p></li><li><p>Khởi chạy ứng dụng. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/Quickstego-0.png" alt="QuickStego-0"></p></li><li><p>Nhấp vào <strong>Open Image</strong>, dưới Picture, Image, Photo File.</p></li><li><p>Chọn hình ảnh bên trong <strong>thư mục QuickStego</strong>. <code>02_nissan_gt-r_specv_opt.jpg</code></p></li><li><p>Tiếp theo, nhấp vào <strong>Open Text</strong> dưới Text File, như hình dưới đây: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/48ad0711987d02ced80915853bf83f9650ae5d18/QuickStego-1.png" alt="QuickStego-1"></p></li><li><p>Chọn <strong>text file.txt</strong> bên trong <strong>thư mục QuickStego</strong>.</p></li><li><p>Văn bản được chọn sẽ được thêm vào ô text ngay cạnh hình ảnh, như hình dưới đây <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/quickStego-2.png" alt="QuickStego-2"></p></li><li><p>Nhấp vào <strong>Hide Text</strong> dưới Steganography <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b3a67a059d4adeff6da89ec1b797b4ee7aa3c1c3/quickstego-3.png" alt="QuickStego-3"></p></li><li><p>Để lưu file hình ảnh (có chứa văn bản bị ẩn), nhấp vào <strong>Save Image</strong>, dưới Picture, Image, Photo File.</p></li></ol><p>File bây giờ được lưu dưới dạng &quot;stego&quot;. Mặc dù có vẻ là một file hình ảnh bình thường, nó có chứa văn bản bị ẩn bên trong, <strong>có thể hiển thị bằng cách xem trong Quick Stego.</strong></p><hr><h1 id="an-du-lieu-su-dung-steghide-kali-linux" tabindex="-1">Ẩn Dữ liệu sử dụng Steghide (Kali Linux) <a class="header-anchor" href="#an-du-lieu-su-dung-steghide-kali-linux" aria-label="Permalink to &quot;Ẩn Dữ liệu sử dụng Steghide (Kali Linux)&quot;">​</a></h1><p>Steghide là chương trình steganography có khả năng ẩn dữ liệu trong nhiều loại file hình ảnh và âm thanh. Tần số màu sắc tương ứng mẫu không bị thay đổi, do đó việc nhúng dữ liệu chống lại các kiểm thử thống kê bậc một.</p><p>Kho lưu trữ chính thức: <a href="https://github.com/StefanoDeVuono/steghide" target="_blank" rel="noreferrer">https://github.com/StefanoDeVuono/steghide</a></p><p>Cài đặt Steghide rất đơn giản trong Kali Linux, vì nó đã có sẵn trong kho lưu trữ Kali Linux.</p><p>Chạy lệnh sau:</p><p><code>sudo apt-get update</code><code>sudo apt-get install steghide</code></p><h3 id="an-van-ban-trong-file-hinh-anh" tabindex="-1">Ẩn Văn bản trong File Hình ảnh <a class="header-anchor" href="#an-van-ban-trong-file-hinh-anh" aria-label="Permalink to &quot;Ẩn Văn bản trong File Hình ảnh&quot;">​</a></h3><ol><li><p>Tạo một thư mục trên Desktop với <strong>file hình ảnh</strong> và <strong>file text bí mật</strong>. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fdcd09b49b5f46b4e9c23ae266b41feadd1e7ce8/steg-kali-0.png" alt="Kali-Steg-Files-0"></p></li><li><p>Để ẩn văn bản trong hình ảnh, điều hướng đến thư mục /Desktop/steg/ và nhập: <code>steghide embed -cf black-cat.jpg -ef secret-text.txt</code><code>-cf</code>: Cover file &lt; filename &gt; <code>-ef</code>: Embedded File &lt; filename &gt; <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c05066032cd10aa55749c47426d139d6abd14e09/Steg-Kali-1.png" alt="Steg-Kali-command"> Lệnh này sẽ nhúng file secret-text.txt vào cover file black-cat.jpg được bảo vệ bằng mật khẩu.</p></li></ol><h3 id="trich-xuat-van-ban-tu-file-hinh-anh" tabindex="-1">Trích xuất văn bản từ File Hình ảnh <a class="header-anchor" href="#trich-xuat-van-ban-tu-file-hinh-anh" aria-label="Permalink to &quot;Trích xuất văn bản từ File Hình ảnh&quot;">​</a></h3><p>Sau khi bạn đã nhúng dữ liệu bí mật, người nhận phải sử dụng steghide theo cách sau:</p><ol><li>Trích xuất Dữ liệu <code>steghide extract -sf black-cat.jpg </code><code>-sf</code>: Stego file</li><li>Nhập mật khẩu chính xác. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/bcbab9ca9f66ea7785cab8e15fc52d5492b0ea2e/KaliStego-3.png" alt="KaliStego-2"> Nội dung của file gốc secret-text.txt sẽ được trích xuất từ stego file black-cat.jpg và lưu trong thư mục hiện tại.</li></ol><h3 id="xem-thong-tin-du-lieu-đuoc-nhung" tabindex="-1">Xem Thông tin Dữ liệu được Nhúng <a class="header-anchor" href="#xem-thong-tin-du-lieu-đuoc-nhung" aria-label="Permalink to &quot;Xem Thông tin Dữ liệu được Nhúng&quot;">​</a></h3><p>Nếu một file chứa dữ liệu được nhúng và bạn muốn lấy thông tin về nó trước khi trích xuất, nhập lệnh:</p><p><code>steghide info black-cat.jpg</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c0fc9841d6bd1d58adbea07cd0b71466cc7bf151/steg-kali-4-embedded.png" alt="Embedded Data"></p><p>Steghide sẽ cố gắng trích xuất dữ liệu được nhúng với mật khẩu đó và - nếu thành công - in một số thông tin về nó.</p><hr><h3 id="danh-du-đe-cap" tabindex="-1">Danh dự đề cập <a class="header-anchor" href="#danh-du-đe-cap" aria-label="Permalink to &quot;Danh dự đề cập&quot;">​</a></h3><p>StegoSuite cho Linux và Windows là công cụ steganography miễn phí và mã nguồn mở được viết bằng Java.</p><p><a href="https://stegosuite.org/" target="_blank" rel="noreferrer">https://stegosuite.org/</a></p>',54)]))}const u=n(i,[["render",o]]);export{d as __pageData,u as default};
